module RefModule(
    input clk,
    input reset,
    output reg [7:0] count
    );
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (reset) begin
            count <= 8'b11111111;
        end else begin
            count <= count - 1;
        end
    end
endmodule
